// Project IDs for active pilot projects
return [
  { json: { project_id: 1, name: '64 Eastwood', code: '64EW' } },
  { json: { project_id: 2, name: '101 Francis', code: '101F' } },
  { json: { project_id: 3, name: '1355 Riverside', code: '1355R' } }
];

const d = $input.first().json;
const h = d.health || 'GREEN';
const emoji = h === 'RED' ? '🔴' : h === 'YELLOW' ? '🟡' : '🟢';
const tasks = d.tasks || {};
const blockers = d.blockers || {};
const procurement = d.procurement || {};
const safety = d.safety || {};

const title = `${emoji} ${d.project_code || ''} SS Brief — ${d.date || ''}`;
const body = [
  `${h} — ${d.project_name}`,
  `Tasks open: ${tasks.open_count || 0} (${tasks.overdue_count || 0} overdue)`,
  `Blockers: ${blockers.count || 0}`,
  `Open bids: ${procurement.open_bids || 0}`,
  `Safety: ${(safety.toolbox_topic || '').split('—')[0].trim()}`,
  `View: http://localhost:8000/superintendent/${d.project_id}`
].join('\n');

const priority = (blockers.count || 0) > 0 || h === 'RED' ? 'high' : 'default';

return [{ json: { title, body, priority } }];
